            if (Array.isArray(value)) {
              for (const v of value) {
                resHeaders.append(key, v);
              }
            } else if (typeof value === 'string') {
              resHeaders.set(key, value);
            }
          }
        }
      }

      return {
        headers: resHeaders,
        status: meta?.status,
